import { serve } from "https://deno.land/std@0.168.0/http/server.ts";

const corsHeaders = {
  "Access-Control-Allow-Origin": "*",
  "Access-Control-Allow-Headers":
    "authorization, x-client-info, apikey, content-type",
};

// Types for Pollinations Response
interface PollinationsSlide {
  slide_number: number;
  type: string;
  heading: string;
  subheading?: string;
  bullets?: string[];
  visual_prompt: string;
  speaker_notes: string;
}

interface PollinationsData {
  presentation_title: string;
  theme: string;
  color_scheme: string;
  slides: PollinationsSlide[];
}

// Helper to clean JSON response from AI
function extractJson(raw: string): string {
  const cleaned = raw.replace(/<think>[\s\S]*?<\/think>/gi, "").trim();
  const start = cleaned.indexOf("{");
  const end = cleaned.lastIndexOf("}");
  if (start !== -1 && end !== -1 && end > start) {
    return cleaned.substring(start, end + 1).trim();
  }
  const fenceRx = /```(?:json)?\s*([\s\S]*?)\s*```/i;
  const m = fenceRx.exec(cleaned);
  if (m?.[1]) return m[1].trim();
  return cleaned;
}

// ✅ TEXT GENERATION using Pollinations (Free, No API Key)
async function generateSlideContent(
  topic: string,
  language: string,
  slideCount: number
): Promise<PollinationsData> {

  const prompt = `You are a professional presentation designer like Gamma.ai.
Generate a complete presentation about "${topic}" in ${language} language.

STRICT RULES:
- Generate exactly ${slideCount} slides
- Slide 1: Title slide (heading + subheading only)
- Slide 2: Agenda/Overview slide
- Slides 3 to ${slideCount - 1}: Detailed content slides
- Slide ${slideCount}: Thank You / Conclusion slide
- Each content slide must have exactly 4 bullet points
- Each bullet point: maximum 12 words
- visual_prompt: detailed, photorealistic, professional image description
- RETURN ONLY PURE JSON. NO MARKDOWN. NO EXTRA TEXT. NO backticks.

REQUIRED JSON FORMAT:
{
  "presentation_title": "string",
  "theme": "professional",
  "color_scheme": "blue-white",
  "slides": [
    {
      "slide_number": 1,
      "type": "title",
      "heading": "string",
      "subheading": "string",
      "visual_prompt": "professional abstract background, blue gradient, corporate, 4K",
      "speaker_notes": "string"
    },
    {
      "slide_number": 2,
      "type": "agenda",
      "heading": "string",
      "bullets": ["Topic 1", "Topic 2", "Topic 3", "Topic 4"],
      "visual_prompt": "clean minimal agenda background, white and blue",
      "speaker_notes": "string"
    },
    {
      "slide_number": 3,
      "type": "content",
      "heading": "string",
      "bullets": [
        "First key point explained briefly",
        "Second important point here",
        "Third point with clear detail",
        "Fourth point summarized well"
      ],
      "visual_prompt": "detailed professional image description for this slide",
      "speaker_notes": "string"
    }
  ]
}`;

  const encodedPrompt = encodeURIComponent(prompt);
  const url = `https://text.pollinations.ai/${encodedPrompt}?model=openai&temperature=0.7&json=true&seed=${Math.floor(Math.random() * 1000000)}`;

  console.log(`Calling Pollinations Text: ${topic}`);

  const response = await fetch(url);

  if (!response.ok) {
    throw new Error(`Text generation failed: ${response.status}`);
  }

  const rawText = await response.text();

  try {
    const cleanText = extractJson(rawText);
    return JSON.parse(cleanText) as PollinationsData;
  } catch (err) {
    const errorMsg = err instanceof Error ? err.message : String(err);
    console.error("JSON Parse Error. Raw text:", rawText.substring(0, 500));
    throw new Error(`Failed to generate valid presentation structure: ${errorMsg}`);
  }
}

// ✅ IMAGE GENERATION using Pollinations (Free, No API Key)
async function generateSlideImage(
  prompt: string,
  slideNumber: number
): Promise<string> {

  const enhancedPrompt = 
    `${prompt}, professional presentation slide background, ` +
    `16:9 aspect ratio, high quality, corporate design, 4K, ` +
    `clean minimal style, no text overlays`;

  const encodedPrompt = encodeURIComponent(enhancedPrompt);

  return `https://image.pollinations.ai/prompt/${encodedPrompt}?width=1280&height=720&model=flux&nologo=true&seed=${Math.floor(Math.random() * 1000) + slideNumber}`;
}

// ✅ MAIN HANDLER
serve(async (req: Request) => {
  if (req.method === "OPTIONS") {
    return new Response("ok", { headers: corsHeaders });
  }

  try {
    const {
      topic,
      language = "English",
      slide_count = 8,
    } = await req.json();

    if (!topic) {
      return new Response(
        JSON.stringify({ error: "Topic is required" }),
        {
          status: 400,
          headers: { ...corsHeaders, "Content-Type": "application/json" },
        }
      );
    }

    console.log(`Generating presentation for: "${topic}"`);

    // STEP 1: Generate slide content via Pollinations Text
    const presentationData = await generateSlideContent(
      topic,
      language,
      slide_count
    );

    // STEP 2: Generate ALL images in PARALLEL via Pollinations Image
    const imageUrls = await Promise.all(
      presentationData.slides.map((slide: PollinationsSlide, index: number) =>
        generateSlideImage(slide.visual_prompt || slide.heading, index + 1)
      )
    );

    // STEP 3: Attach image URLs and CONVERT to legacy "blocks" format for compatibility
    const slidesWithImages = presentationData.slides.map(
      (slide: PollinationsSlide, index: number) => {
        const imageUrl = imageUrls[index];

        const blocks = [];

        blocks.push({
          id: `h-${crypto.randomUUID()}`,
          type: slide.type === "title" ? "heading1" : "heading2",
          content: slide.heading || topic
        });

        if (slide.subheading) {
          blocks.push({
            id: `p-${crypto.randomUUID()}`,
            type: "paragraph",
            content: slide.subheading
          });
        }

        if (slide.bullets && Array.isArray(slide.bullets)) {
          blocks.push({
            id: `b-${crypto.randomUUID()}`,
            type: "bulletList",
            content: slide.bullets
          });
        }

        blocks.push({
          id: `i-${crypto.randomUUID()}`,
          type: "image",
          content: imageUrl,
          metadata: { imagePrompt: slide.visual_prompt }
        });

        return {
          id: `s-${crypto.randomUUID()}`,
          slide_number: slide.slide_number,
          type: slide.type,
          layout: slide.type === "title" ? "hero" : "image-text",
          title: slide.heading,
          blocks: blocks,
          image_url: imageUrl,
          speakerNotes: slide.speaker_notes
        };
      }
    );

    const finalResponse = {
      success: true,
      title: presentationData.presentation_title || topic,
      presentation_title: presentationData.presentation_title || topic,
      theme: presentationData.theme || "professional",
      color_scheme: presentationData.color_scheme || "blue-white",
      total_slides: slidesWithImages.length,
      slides: slidesWithImages,
    };

    return new Response(JSON.stringify(finalResponse), {
      headers: { ...corsHeaders, "Content-Type": "application/json" },
    });

  } catch (err: unknown) {
    const error = err instanceof Error ? err : new Error(String(err));
    console.error("Generation error:", error);
    return new Response(
      JSON.stringify({
        error: "Generation failed",
        details: error.message,
      }),
      {
        status: 500,
        headers: { ...corsHeaders, "Content-Type": "application/json" },
      }
    );
  }
});
